window.docContents[47].resolve({"/Citations/#Zippers___-A-Documentation-Example--Citations":{"contents":"Cite works using citet, citep, or citehere.\nThey take a name of a citable reference value as a parameter.\nReferences should be defined as values, typically in one module that is imported (similar to the role of a .bib file in LaTeX).\n\nTextual citations, as with , look like this.\nParenthetical  looks like this.\nUse citehere to literally include the cite rather than making a margin note, e.g. .\nLiterally-included cites are mostly useful when performing citation inside a margin note.\n\n","context":"Zippers: A Documentation Example","header":"4. Citations","id":"/Citations/#Zippers___-A-Documentation-Example--Citations"}});